const data = $input.first().json.data;

const removals = Object.entries(data)
  .filter(([key, value]) => value.includes("Remove from meal plan"))
  .map(([key]) => {
    // Format: "2026-03-04 — Recipe Name - 148"
    const lastDash = key.lastIndexOf(' - ');
    const id = key.substring(lastDash + 3).trim();
    const withoutId = key.substring(0, lastDash).trim();

    const [date, ...nameParts] = withoutId.split(' — ');
    return {
      id,
      date: date.trim(),
      recipeName: nameParts.join(' — ').trim()
    };
  });

return [{
  json: {
    removals,
    isEmpty: removals.length === 0
  }
}];

const days = [];
const today = new Date($now.toFormat('yyyy-MM-dd'));
for (let i = 0; i < 7; i++) {
  const date = new Date(today);
  date.setDate(today.getDate() + i);
  days.push({
    json: {
      date: date.toISOString().split("T")[0],
      dayOfWeek: date.toLocaleDateString("en-US", { weekday: "long" }),
    }
  });
}
return days;

// N8N Code Node - Meal Plan Email Generator
// Input: the meal plan JSON from your previous node
// Output: { html: "..." } for the Gmail node

const items = $input.first().json.items;

const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];

function formatDate(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  return {
    weekday: days[d.getDay()],
    date: d.toLocaleDateString('en-US', { month: 'long', day: 'numeric' })
  };
}

function shortDesc(text) {
  // Pull out just the first sentence for a clean summary
  const first = text.split('. ')[0];
  return first.length > 160 ? first.substring(0, 157) + '...' : first;
}

function extractStats(desc) {
  const cal = desc.match(/(\d+)\s*calories/i);
  const protein = desc.match(/(\d+)g of protein/i);
  const time = null; // pulled from recipe directly
  return {
    calories: cal ? cal[1] : null,
    protein: protein ? protein[1] : null,
  };
}

const mealRows = items.map(item => {
  const { weekday, date } = formatDate(item.date);
  const recipe = item.recipe;
  const stats = extractStats(recipe.description);
  const desc = shortDesc(recipe.description);

  const statBadges = [
    recipe.totalTime ? `⏱ ${recipe.totalTime}` : null,
    stats.calories ? `🔥 ${stats.calories} cal` : null,
    stats.protein ? `💪 ${stats.protein}g protein` : null,
    recipe.recipeServings ? `🍽 Serves ${recipe.recipeServings}` : null,
  ].filter(Boolean).map(b => `<span style="display:inline-block;background:#f0ebe1;color:#7a5c38;font-size:11px;font-weight:500;padding:3px 9px;border-radius:20px;margin:2px 3px 2px 0;">${b}</span>`).join('');

  return `
    <tr>
      <td style="padding:0 0 14px 0;">
        <table width="100%" cellpadding="0" cellspacing="0" style="background:#ffffff;border:1px solid #e8dfd0;border-radius:12px;overflow:hidden;">
          <tr>
            <td style="background:#2c2416;width:80px;text-align:center;padding:16px 10px;vertical-align:top;">
              <div style="font-family:'Georgia',serif;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.1em;color:#c9a96e;line-height:1.2;">${weekday.substring(0,3)}</div>
              <div style="font-family:'Georgia',serif;font-size:22px;font-weight:700;color:#fdf8f0;line-height:1.1;margin-top:2px;">${new Date(item.date + 'T00:00:00').getDate()}</div>
              <div style="font-family:'Georgia',serif;font-size:10px;color:#a89070;margin-top:2px;">${new Date(item.date + 'T00:00:00').toLocaleDateString('en-US',{month:'short'})}</div>
            </td>
            <td style="padding:16px 20px;vertical-align:top;">
              <div style="font-family:'Georgia',serif;font-size:16px;font-weight:700;color:#2c2416;margin-bottom:6px;">${recipe.name}</div>
              <div style="margin-bottom:8px;">${statBadges}</div>
              <div style="font-size:13px;color:#6b5740;line-height:1.6;">${desc}.</div>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  `;
}).join('');

const selectOptions = items.map(item => {
  const { weekday } = formatDate(item.date);
  return `<option value="${item.id}|${item.recipeId}|${item.date}">${weekday} – ${item.recipe.name}</option>`;
}).join('\n');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1.0"/>
</head>
<body style="margin:0;padding:32px 16px;background-color:#f5f0e8;font-family:'Helvetica Neue',Arial,sans-serif;color:#2c2416;">
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr><td align="center">
      <table width="620" cellpadding="0" cellspacing="0" style="max-width:620px;width:100%;">

        <!-- Header -->
        <tr>
          <td style="background:#2c2416;border-radius:16px 16px 0 0;padding:36px 40px 28px;text-align:center;">
            <div style="font-size:11px;font-weight:600;letter-spacing:0.2em;text-transform:uppercase;color:#c9a96e;margin-bottom:10px;">Weekly Dinner Plan</div>
            <div style="font-family:'Georgia',serif;font-size:28px;font-weight:700;color:#fdf8f0;line-height:1.2;">This Week's Dinners</div>
            <div style="margin-top:10px;font-size:14px;color:#a89070;">Review your meals below, then let us know if you'd like to swap anything out.</div>
          </td>
        </tr>

        <!-- Body -->
        <tr>
          <td style="background:#fdf8f0;padding:32px 40px;">

            <!-- Intro -->
            <p style="font-size:14.5px;line-height:1.7;color:#5a4a35;margin:0 0 24px 0;padding-bottom:24px;border-bottom:1px solid #e8dfd0;">
              Here's your dinner lineup for the week. Take a look at each meal, and if anything doesn't appeal to you, use the form below to flag it for replacement.
            </p>

            <!-- Meal Cards -->
            <table width="100%" cellpadding="0" cellspacing="0">
              ${mealRows}
            </table>

            <!-- Divider -->
            <table width="100%" cellpadding="0" cellspacing="0" style="margin:8px 0 28px;">
              <tr><td style="border-top:1px dashed #d4c8b5;font-size:0;">&nbsp;</td></tr>
            </table>
          </td>
        </tr>
      </table>
    </td></tr>
  </table>
</body>
</html>`;

const fields = items.map(item => ({
  fieldLabel: `${item.date} — ${item.recipe.name} - ${item.id}`,
  fieldType: "checkbox",
  fieldOptions: {
    values: [
      {
        option: "Remove from meal plan"
      }
    ]
  }
}));

return [{ json: { html, fields } }];
